# Способ 2 (лучше): lru_cache + оптимизированный базовый случай
from functools import lru_cache

@lru_cache(maxsize=None)
def f(n):
    # Поднимаем базовый случай чтобы цепочка была короткой
    if n < 257000:   # вместо n < 10
        return 3
    return (n + 4) * f(n - 5)

